fun solve(n: Long, k: Long): Long {
    // Precompute the popcount-depth for numbers up to 63 (since 2^63 is larger than 1e15)
    // We'll use memoization to store the depth for each number
    val memo = mutableMapOf<Long, Long>()

    fun popcount(x: Long): Int {
        var count = 0
        var num = x
        while (num > 0) {
            count += num.and(num - 1).also { num = it }
        }
        return count
    }

    fun depth(x: Long): Long {
        return memo.getOrPut(x) {
            if (popcount(x) == 1L) 1L
            else 1L + depth(popcount(x))
        }
    }

    // Count numbers in [1, n] with popcount-depth exactly equal to k
    var count = 0L
    for (x in 1L..n) {
        if (depth(x) == k) {
            count++
        }
    }
    return count
}
